 * Service for executing user-provided Groovy scripts.
 */
public class ScriptService {

    /**
     * Executes a user-provided Groovy script and returns the result.
     *
     * @param scriptContent the Groovy script content to execute
     * @return the result of the script execution
     * @throws IllegalArgumentException if the script content is null or empty
     * @throws RuntimeException if the script execution fails
     */
    public Object executeUserScript(String scriptContent) {
        if (scriptContent == null || scriptContent.trim().isEmpty()) {
            throw new IllegalArgumentException("Script content cannot be null or empty");
        }

        try {
            GroovyShell shell = new GroovyShell();
            Script script = shell.parse(scriptContent);
            return script.run();
        } catch (Exception e) {
            throw new RuntimeException("Failed to execute Groovy script: " + e.getMessage(), e);
        }
    }
}
